class Solution(object):
    def postorderTraversal(self, root):
        result = []
        stack = []
        last_visited = None
        node = root
        while node or stack:
            while node:
                stack.append(node)
                node = node.left
            peek = stack[-1]
            if peek.right and peek.right != last_visited:
                node = peek.right
            else:
                result.append(peek.val)
                last_visited = stack.pop()
        return result
